import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import { TextField, Button, Typography, Box } from "@mui/material";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [drug, setDrug] = useState({
        code: "",
        name: "",
        typeId: "",
        price: "",
        unit: "",
        description: "",
    });

    // Gọi API lấy thông tin thuốc cũ
    useEffect(() => {
        axios
            .get(`http://localhost:5000/api/drugs/${id}`)
            .then((response) => {
                setDrug(response.data); // Gán dữ liệu cũ vào state
            })
            .catch((error) => console.error("Lỗi khi lấy dữ liệu thuốc:", error));
    }, [id]);

    // Xử lý khi thay đổi input
    const handleChange = (e) => {
        setDrug({ ...drug, [e.target.name]: e.target.value });
    };

    // Gửi dữ liệu cập nhật
    const handleSubmit = (e) => {
        e.preventDefault();
        axios
            .put(`http://localhost:5000/api/drugs/${id}`, drug)
            .then(() => navigate("/drugs")) // Quay lại danh sách thuốc
            .catch((error) => console.error("Lỗi khi cập nhật thuốc:", error));
    };

    return (
        <Box sx={{ maxWidth: 600, margin: "auto", mt: 4 }}>
            <Typography variant="h4" gutterBottom>
                Chỉnh sửa thuốc
            </Typography>
            <form onSubmit={handleSubmit}>
                <TextField
                    fullWidth
                    label="Mã thuốc"
                    name="code"
                    value={drug.code}
                    onChange={handleChange}
                    margin="normal"
                    required
                />
                <TextField
                    fullWidth
                    label="Tên thuốc"
                    name="name"
                    value={drug.name}
                    onChange={handleChange}
                    margin="normal"
                    required
                />
                <TextField
                    fullWidth
                    label="ID loại thuốc"
                    name="typeId"
                    value={drug.typeId}
                    onChange={handleChange}
                    margin="normal"
                    required
                />
                <TextField
                    fullWidth
                    label="Giá"
                    name="price"
                    value={drug.price}
                    onChange={handleChange}
                    margin="normal"
                    required
                />
                <TextField
                    fullWidth
                    label="Đơn vị"
                    name="unit"
                    value={drug.unit}
                    onChange={handleChange}
                    margin="normal"
                    required
                />
                <TextField
                    fullWidth
                    label="Mô tả"
                    name="description"
                    value={drug.description}
                    onChange={handleChange}
                    margin="normal"
                    multiline
                    rows={3}
                    required
                />
                <Box sx={{ mt: 2, display: "flex", justifyContent: "space-between" }}>
                    <Button variant="contained" color="secondary" onClick={() => navigate("/drugs")}>
                        Quay lại
                    </Button>
                    <Button type="submit" variant="contained" color="primary">
                        Lưu lại
                    </Button>
                </Box>
            </form>
        </Box>
    );
};

export default EditDrug;
